  const STATUSBAR_LOCAL_TRANSLATIONS_SORTED = STATUSBAR_LOCAL_TRANSLATIONS
    .slice()
    .sort((a, b) => String(b[0]).length - String(a[0]).length);

  const getStatusBarHost = () => {
    try { return window.parent || window; } catch (e) { return window; }
  };

  const cloneStatusBarData = (value) => {
    if (value === null || value === undefined) return value;
    try {
      if (typeof structuredClone === 'function') return structuredClone(value);
    } catch (e) { }
    try { return JSON.parse(JSON.stringify(value)); } catch (e) { return value; }
  };

  const translateStatusBarRuntimeText = (value) => {
    if (typeof value !== 'string') return value;
    let out = value;
    try {
      const host = getStatusBarHost();
      if (typeof host.__card36TranslateRuntimeText === 'function') {
        out = host.__card36TranslateRuntimeText(out);
      }
    } catch (e) { }
    for (const [from, to] of STATUSBAR_LOCAL_TRANSLATIONS_SORTED) {
      if (out.includes(from)) out = out.split(from).join(to);
    }
    return out;
  };

  const resolveStatusBarSourceText = (value) => {
    if (typeof value !== 'string') return value;
    const text = value.trim();
    for (const [from, to] of STATUSBAR_LOCAL_TRANSLATIONS) {
      if (text === to) return from;
    }
    return text;
  };

  const prepareStatusBarRuntimeData = (statData) => {
    const cloned = cloneStatusBarData(statData);
    try {
      const host = getStatusBarHost();
      if (typeof host.__card36PrepareCalculatorRuntimeData === 'function') {
        return host.__card36PrepareCalculatorRuntimeData(cloned);
      }
    } catch (e) {
      try { console.warn('[RPG StatusBar]', 'Chuẩn bị dữ liệu status bar thất bại:', e); } catch (_) { }
    }
    return cloned || {};
  };

  const restoreStatusBarRuntimeData = (value) => {
    const cloned = cloneStatusBarData(value);
    try {
      const host = getStatusBarHost();
      if (typeof host.__card36RestoreCalculatorRuntimeData === 'function') {
        return host.__card36RestoreCalculatorRuntimeData(cloned);
      }
    } catch (e) {
      try { console.warn('[RPG StatusBar]', 'Khôi phục dữ liệu status bar thất bại:', e); } catch (_) { }
    }
    return cloned;
  };

  const encodeJsonPointerToken = (token) => String(token || '').replace(/~/g, '~0').replace(/\//g, '~1');

  const restoreStatusBarPatchPath = (path) => {
    if (typeof path !== 'string' || !path.startsWith('/')) return path;
    const parts = splitPatchPath(path);
    return '/' + parts.map(part => encodeJsonPointerToken(translateStatusBarRuntimeText(part))).join('/');
  };

  const restoreStatusBarPatchForWrite = (patch) => {
    if (!patch || typeof patch !== 'object') return patch;
    const nextPatch = { ...patch, path: restoreStatusBarPatchPath(patch.path) };
    if (Object.prototype.hasOwnProperty.call(nextPatch, 'value')) {
      nextPatch.value = restoreStatusBarRuntimeData(nextPatch.value);
    }
    return nextPatch;
  };

  const localizeStatusBarDom = (root = null) => {
    try {
      const { window: win } = getCore();
      const doc = win.document || document;
      const rootEl = root || doc.getElementById(`${SCRIPT_ID}-panel`) || doc.getElementById(`${SCRIPT_ID}-toggle`);
      if (!rootEl) return;
      const nodeFilter = win.NodeFilter || NodeFilter;
      const skipTags = new Set(['SCRIPT', 'STYLE', 'TEXTAREA', 'CODE', 'PRE', 'SVG']);
      const walker = doc.createTreeWalker(rootEl, nodeFilter.SHOW_TEXT, {
        acceptNode(node) {
          const parent = node.parentElement;
          if (!parent || skipTags.has(parent.tagName)) return nodeFilter.FILTER_REJECT;
          return /[\u3400-\u9fff]/.test(node.nodeValue || '') ? nodeFilter.FILTER_ACCEPT : nodeFilter.FILTER_REJECT;
        }
      });
      const textNodes = [];
      while (walker.nextNode()) textNodes.push(walker.currentNode);
      textNodes.forEach(node => {
        const next = translateStatusBarRuntimeText(node.nodeValue || '');
        if (next !== node.nodeValue) node.nodeValue = next;
      });
      if (rootEl.querySelectorAll) {
        rootEl.querySelectorAll('[title], [aria-label], [placeholder], [value]').forEach(el => {
          ['title', 'aria-label', 'placeholder', 'value'].forEach(attr => {
            if (!el.hasAttribute(attr)) return;
            const cur = el.getAttribute(attr);
            if (!cur || !/[\u3400-\u9fff]/.test(cur)) return;
            const next = translateStatusBarRuntimeText(cur);
            if (next !== cur) el.setAttribute(attr, next);
          });
        });
      }
    } catch (e) { }
  };

