  const QUALITY_NAME_INPUT_MAP = Object.freeze({
    'Thường': '\u666E\u901A',
    'Tinh xảo': '\u7CBE\u826F',
    'Hiếm': '\u7A00\u6709',
    'Xuất sắc': '\u5353\u8D8A',
    'Thần khí': '\u795E\u5668',
    'Truyền thuyết': '\u4F20\u8BF4',
    'Sử thi': '\u53F2\u8BD7',
    'Thần thoại': '\u795E\u8BDD'
  });
  const normalizeQualityName = (value) => {
    const raw = String(value ?? '').trim();
    const normalized = QUALITY_NAME_INPUT_MAP[raw] || raw;
    return normalized === '\u795E\u5668' ? '\u5353\u8D8A' : normalized;
  };

